-- Are customers who are repeat buyers( more than 5 previous purchases)also likely to subsribe?
select subscription_status,
count(customer_id) as repeat_buyers
from cust
where previous_purchases > 5
group by subscription_status;


-- What are the revenue contribution of each age group?

select age_group, 
sum(purchase_amount) as Revenue_contribution
from cust
group by age_group;


